    'spintriae' => 
    array (
      'title' => 'Tessères romaines avec chiffres et spintriae',
      'lead' => 'Oggetti numismatici e tessere con numerali romani.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
