        2 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => 'botton_07.jpg',
            'alt' => '',
            'link' => 'https://shop.moruzzi.it/fr/monnaies/monnaies-de-la-republique-italienne.html',
