    'byzantine_solidus' => 
    array (
      'title' => 'Le solide byzantin',
      'lead' => 'Il solido nell\'Impero bizantino.',
      'blocks' => 
      array (
        0 => 
        array (
          'type' => 'figure',
          'image' => 
          array (
            'file' => '3a.jpg',
